-- Decoder — seed_all.sql: run AFTER concepts.sql + concepts_search.sql.
-- Contains every glossary term (original 15 + all generated batches). Idempotent.

-- Decoder — seed the shelf from the original 15 hand-authored terms.
-- Generated from web/concepts.js. Run AFTER concepts.sql.
-- Idempotent: re-running updates existing rows (upsert on id).

on conflict (id) do update set
  term=excluded.term, aliases=excluded.aliases, said=excluded.said,
  alias_list=excluded.alias_list, status=excluded.status, one_liner=excluded.one_liner,
  analogy=excluded.analogy, example=excluded.example, related=excluded.related,
  deeper=excluded.deeper, lens_pm=excluded.lens_pm, lens_eng=excluded.lens_eng,
  updated_at=now();

